326→func TestClaims_NormalizedRoles(t *testing.T) {
327→	t.Parallel()
328→	tests := []struct {
329→		name  string
330→		roles []string
331→		role  string
332→		want  []string
333→	}{
334→		{"both empty", nil, "", nil},
335→		{"roles only", []string{"admin"}, "", []string{"admin"}},
336→		{"role only", nil, "authenticated", []string{"authenticated"}},
337→		{"both no overlap", []string{"admin"}, "authenticated", []string{"admin", "authenticated"}},
338→		{"both with overlap", []string{"admin", "authenticated"}, "authenticated", []string{"admin", "authenticated"}},
339→		{"duplicate in roles", []string{"admin", "admin"}, "", []string{"admin"}},
340→	}
341→	for _, tt := range tests {
342→		t.Run(tt.name, func(t *testing.T) {
343→			t.Parallel()
344→			c := &Claims{Roles: tt.roles, Role: tt.role}
345→			got := c.NormalizedRoles()
346→			if len(got) != len(tt.want) {
347→				t.Fatalf("NormalizedRoles() = %v, want %v", got, tt.want)
348→			}
349→			for i := range got {
350→				if got[i] != tt.want[i] {
351→					t.Errorf("NormalizedRoles()[%d] = %q, want %q", i, got[i], tt.want[i])
352→				}
353→			}
354→		})
355→	}
356→}
