package auth

import (
	"crypto/rsa"
	"errors"
	"fmt"

	"github.com/golang-jwt/jwt/v5"
)

// Claims extends jwt.RegisteredClaims with application-specific fields.
type Claims struct {
	jwt.RegisteredClaims
	Email        string         `json:"email,omitempty"`
	Roles        []string       `json:"roles,omitempty"`
	Role         string         `json:"role,omitempty"`          // Supabase: "authenticated", "anon", etc.
	TeamID       string         `json:"team_id,omitempty"`
	ClientType   string         `json:"client_type,omitempty"`   // web|cli|mobile|desktop
	AppMetadata  map[string]any `json:"app_metadata,omitempty"`  // Supabase: provider info
	UserMetadata map[string]any `json:"user_metadata,omitempty"` // Supabase: user profile data
}

// NormalizedRoles returns a deduplicated union of Roles and the singular Role field.
func (c *Claims) NormalizedRoles() []string {
	seen := make(map[string]struct{}, len(c.Roles)+1)
	var result []string
	for _, r := range c.Roles {
		if _, ok := seen[r]; !ok {
			seen[r] = struct{}{}
			result = append(result, r)
		}
	}
	if c.Role != "" {
		if _, ok := seen[c.Role]; !ok {
			result = append(result, c.Role)
		}
	}
	return result
}

// Provider extracts the authentication provider from AppMetadata.
// Returns an empty string if the provider is not set or is not a string.
func (c *Claims) Provider() string {
	if c.AppMetadata == nil {
		return ""
	}
	p, _ := c.AppMetadata["provider"].(string)
	return p
}

// Validator validates a JWT token string and returns parsed claims.
type Validator interface {
	Validate(tokenString string) (*Claims, error)
}

// HMACValidator validates HS256 tokens using a shared secret.
type HMACValidator struct {
	secret     []byte
	parserOpts []jwt.ParserOption
}

// NewHMACValidator creates a Validator using HS256 with the provided secret.
func NewHMACValidator(secret string, opts ...jwt.ParserOption) *HMACValidator {
	return &HMACValidator{
		secret:     []byte(secret),
		parserOpts: opts,
	}
}

// Validate parses and validates an HS256 JWT token string.
func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
	claims := &Claims{}
	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
		}
		return v.secret, nil
	}, v.parserOpts...)
	if err != nil {
		return nil, fmt.Errorf("auth: token validation failed: %w", err)
	}
	if !token.Valid {
		return nil, errors.New("auth: token is not valid")
	}
	return claims, nil
}

// RSAValidator validates RS256 tokens using an RSA public key.
type RSAValidator struct {
	publicKey  *rsa.PublicKey
	parserOpts []jwt.ParserOption
}

// NewRSAValidator creates a Validator using RS256 with the provided PEM public key.
func NewRSAValidator(pemPublicKey string, opts ...jwt.ParserOption) (*RSAValidator, error) {
	key, err := jwt.ParseRSAPublicKeyFromPEM([]byte(pemPublicKey))
	if err != nil {
		return nil, fmt.Errorf("auth: failed to parse RSA public key: %w", err)
	}
	return &RSAValidator{
		publicKey:  key,
		parserOpts: opts,
	}, nil
}

// Validate parses and validates an RS256 JWT token string.
func (v *RSAValidator) Validate(tokenString string) (*Claims, error) {
	claims := &Claims{}
	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
		if _, ok := t.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
		}
		return v.publicKey, nil
	}, v.parserOpts...)
	if err != nil {
		return nil, fmt.Errorf("auth: token validation failed: %w", err)
	}
	if !token.Valid {
		return nil, errors.New("auth: token is not valid")
	}
	return claims, nil
}

package main

import (
	"context"
	"log/slog"
	"os"
	"os/signal"
	"syscall"

	"github.com/golang-jwt/jwt/v5"
	"github.com/joho/godotenv"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	"github.com/ketang/kapow/api/internal/db"
	kapowmiddleware "github.com/ketang/kapow/api/internal/middleware"
	kapowotel "github.com/ketang/kapow/api/internal/otel"
	"github.com/ketang/kapow/api/internal/preference"
	"github.com/ketang/kapow/api/internal/router"
	"github.com/ketang/kapow/api/internal/search"
	"github.com/ketang/kapow/api/internal/server"
	"github.com/ketang/kapow/api/internal/user"
	"github.com/ketang/kapow/api/internal/version"
	"github.com/ketang/kapow/api/ui"
)

func main() {
	// 1. Load .env (no-op if file is absent — dev only)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting kapow api", "version", version.Version, "build_time", version.BuildTime, "env", cfg.Env)

	// 4. Initialize OpenTelemetry (opt-in via OTEL_ENABLED)
	ctx := context.Background()
	mp, tp, err := kapowotel.Init(ctx, kapowotel.Config{
		Enabled:     cfg.OTelEnabled,
		ServiceName: "kapow-api",
		Version:     version.Version,
		Environment: cfg.Env,
	})
	if err != nil {
		slog.Error("failed to initialize OpenTelemetry", "error", err)
		os.Exit(1)
	}
	defer func() {
		if err := kapowotel.Shutdown(ctx, mp, tp); err != nil {
			slog.Error("otel shutdown error", "error", err)
		}
	}()
	if cfg.OTelEnabled {
		slog.Info("otel: initialized", "service", "kapow-api")
	}

	// 5. Connect to database
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error; OS reclaims resources
	}
	defer pool.Close()

	// 6. Select JWT validator
	var jwtOpts []jwt.ParserOption
	if cfg.JWTIssuer != "" {
		jwtOpts = append(jwtOpts, jwt.WithIssuer(cfg.JWTIssuer))
	}
	if cfg.JWTAudience != "" {
		jwtOpts = append(jwtOpts, jwt.WithAudience(cfg.JWTAudience))
	}

	var validator auth.Validator
	if cfg.JWTPublicKey != "" {
		validator, err = auth.NewRSAValidator(cfg.JWTPublicKey, jwtOpts...)
		if err != nil {
			slog.Error("failed to create RSA JWT validator", "error", err)
			os.Exit(1) //nolint:gocritic // fatal startup error; OS reclaims resources
		}
		slog.Info("auth: using RS256 JWT validator")
	} else {
		validator = auth.NewHMACValidator(cfg.JWTSecret, jwtOpts...)
		slog.Info("auth: using HS256 JWT validator")
	}

	// 7. Parse private endpoint CIDR allowlist
	privateCIDRs, err := kapowmiddleware.ParseCIDRs(cfg.PrivateAllowlistCIDRs)
	if err != nil {
		slog.Error("failed to parse PRIVATE_ALLOWLIST_CIDRS", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error; OS reclaims resources
	}
	slog.Info("private endpoint allowlist configured", "cidrs", cfg.PrivateAllowlistCIDRs)

	// 8. Build router
	userSvc := user.NewService(pool)
	prefSvc := preference.NewService(pool)

	// Resolve embedded UI assets (nil when built without -tags ui).
	uiFS := ui.Assets()
	if uiFS != nil {
		slog.Info("embedded UI assets loaded")
	}

	r := router.New(router.Deps{
		Config:            cfg,
		DB:                pool,
		Validator:         validator,
		Search:            search.NewRegistry(),
		UserService:       userSvc,
		PreferenceService: prefSvc,
		PrivateCIDRs:      privateCIDRs,
		UI:                uiFS,
	})

	// 9. Build HTTP server
	srv := server.New(cfg, r)

	// 10. Listen for OS signals
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	// 11. Start server in background goroutine
	go func() {
		slog.Info("server: listening", "addr", cfg.Addr())
		if err := srv.ListenAndServe(); err != nil {
			// ErrServerClosed is expected during graceful shutdown
			slog.Info("server: stopped", "reason", err)
		}
	}()

	// 12. Block until signal received
	sig := <-sigCh
	slog.Info("signal received", "signal", sig)

	// 13. Graceful shutdown
	if err := server.Shutdown(srv, cfg.ShutdownTimeout); err != nil {
		slog.Error("server: shutdown error", "error", err)
		os.Exit(1)
	}
}

