package auth

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"strings"
	"testing"
	"time"

	"github.com/golang-jwt/jwt/v5"
)

func makeHMACToken(t *testing.T, secret string, claims Claims) string {
	t.Helper()
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &claims)
	s, err := token.SignedString([]byte(secret))
	if err != nil {
		t.Fatalf("sign token: %v", err)
	}
	return s
}

func TestHMACValidator_ValidToken(t *testing.T) {
	t.Parallel()
	secret := "test-secret-key"
	v := NewHMACValidator(secret)

	claims := Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   "user-123",
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
			IssuedAt:  jwt.NewNumericDate(time.Now()),
		},
		Email:      "user@example.com",
		Roles:      []string{"admin"},
		TeamID:     "team-1",
		ClientType: "web",
	}

	tokenStr := makeHMACToken(t, secret, claims)
	got, err := v.Validate(tokenStr)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if got.Subject != "user-123" {
		t.Errorf("subject = %q, want %q", got.Subject, "user-123")
	}
	if got.Email != "user@example.com" {
		t.Errorf("email = %q, want %q", got.Email, "user@example.com")
	}
	if len(got.Roles) != 1 || got.Roles[0] != "admin" {
		t.Errorf("roles = %v, want [admin]", got.Roles)
	}
	if got.TeamID != "team-1" {
		t.Errorf("team_id = %q, want %q", got.TeamID, "team-1")
	}
	if got.ClientType != "web" {
		t.Errorf("client_type = %q, want %q", got.ClientType, "web")
	}
}

func TestHMACValidator_ExpiredToken(t *testing.T) {
	t.Parallel()
	secret := "test-secret-key"
	v := NewHMACValidator(secret)

	claims := Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   "user-123",
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(-time.Hour)),
		},
	}

	tokenStr := makeHMACToken(t, secret, claims)
	_, err := v.Validate(tokenStr)
	if err == nil {
		t.Fatal("expected error for expired token")
	}
	if !strings.Contains(err.Error(), "token validation failed") {
		t.Errorf("error = %q, want to contain 'token validation failed'", err.Error())
	}
}

func TestHMACValidator_WrongSecret(t *testing.T) {
	t.Parallel()
	v := NewHMACValidator("correct-secret")

	claims := Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   "user-123",
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
		},
	}

	tokenStr := makeHMACToken(t, "wrong-secret", claims)
	_, err := v.Validate(tokenStr)
	if err == nil {
		t.Fatal("expected error for wrong secret")
	}
}

func TestHMACValidator_RSASignedToken(t *testing.T) {
	t.Parallel()
	// An RSA-signed token should be rejected by the HMAC validator.
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("generate key: %v", err)
	}

	claims := Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   "user-123",
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
		},
	}
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, &claims)
	tokenStr, err := token.SignedString(key)
	if err != nil {
		t.Fatalf("sign token: %v", err)
	}

	v := NewHMACValidator("some-secret")
	_, err = v.Validate(tokenStr)
	if err == nil {
		t.Fatal("expected error for RSA-signed token on HMAC validator")
	}
	if !strings.Contains(err.Error(), "unexpected signing method") {
		t.Errorf("error = %q, want to contain 'unexpected signing method'", err.Error())
	}
}

func TestHMACValidator_MalformedToken(t *testing.T) {
	t.Parallel()
	v := NewHMACValidator("secret")
	_, err := v.Validate("not-a-jwt")
	if err == nil {
		t.Fatal("expected error for malformed token")
	}
}

// --- RSA validator tests ---

func generateRSAKeyPair(t *testing.T) (*rsa.PrivateKey, string) {
	t.Helper()
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("generate RSA key: %v", err)
	}
	pubBytes, err := x509.MarshalPKIXPublicKey(&key.PublicKey)
	if err != nil {
		t.Fatalf("marshal RSA public key: %v", err)
	}
	pemBlock := pem.EncodeToMemory(&pem.Block{Type: "PUBLIC KEY", Bytes: pubBytes})
	return key, string(pemBlock)
}

func makeRSAToken(t *testing.T, key *rsa.PrivateKey, claims Claims) string {
	t.Helper()
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, &claims)
	s, err := token.SignedString(key)
	if err != nil {
		t.Fatalf("sign RSA token: %v", err)
	}
	return s
}

func TestRSAValidator_ValidToken(t *testing.T) {
	t.Parallel()
	key, pem := generateRSAKeyPair(t)
	v, err := NewRSAValidator(pem)
	if err != nil {
		t.Fatalf("NewRSAValidator: %v", err)
	}

	claims := Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   "rsa-user",
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
		},
		Email: "rsa@example.com",
	}

	tokenStr := makeRSAToken(t, key, claims)
	got, err := v.Validate(tokenStr)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if got.Subject != "rsa-user" {
		t.Errorf("subject = %q, want %q", got.Subject, "rsa-user")
