	"github.com/golang-jwt/jwt/v5"
)

func makeHMACToken(t *testing.T, secret string, claims Claims) string {
	t.Helper()
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &claims)
	s, err := token.SignedString([]byte(secret))
	if err != nil {
		t.Fatalf("sign token: %v", err)
	}
	return s
}

func TestHMACValidator_ValidToken(t *testing.T) {
	t.Parallel()
	secret := "test-secret-key"
	v := NewHMACValidator(secret)

	claims := Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			Subject:   "user-123",
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
			IssuedAt:  jwt.NewNumericDate(time.Now()),
		},
		Email:      "user@example.com",
		Roles:      []string{"admin"},
		TeamID:     "team-1",
		ClientType: "web",
	}

	tokenStr := makeHMACToken(t, secret, claims)
	got, err := v.Validate(tokenStr)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if got.Subject != "user-123" {
		t.Errorf("subject = %q, want %q", got.Subject, "user-123")
	}
	if got.Email != "user@example.com" {
		t.Errorf("email = %q, want %q", got.Email, "user@example.com")
	}
	if len(got.Roles) != 1 || got.Roles[0] != "admin" {
		t.Errorf("roles = %v, want [admin]", got.Roles)
	}
	if got.TeamID != "team-1" {
		t.Errorf("team_id = %q, want %q", got.TeamID, "team-1")
	}
	if got.ClientType != "web" {
		t.Errorf("client_type = %q, want %q", got.ClientType, "web")
	}
}

