	tests := []struct {
		name  string
		roles []string
		role  string
		want  []string
	}{
		{"both empty", nil, "", nil},
		{"roles only", []string{"admin"}, "", []string{"admin"}},
		{"role only", nil, "authenticated", []string{"authenticated"}},
		{"both no overlap", []string{"admin"}, "authenticated", []string{"admin", "authenticated"}},
		{"both with overlap", []string{"admin", "authenticated"}, "authenticated", []string{"admin", "authenticated"}},
		{"duplicate in roles", []string{"admin", "admin"}, "", []string{"admin"}},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			c := &Claims{Roles: tt.roles, Role: tt.role}
			got := c.NormalizedRoles()
			if len(got) != len(tt.want) {
				t.Fatalf("NormalizedRoles() = %v, want %v", got, tt.want)
